class Solution:
    def minZeroArray(self, nums, queries):
        n = len(nums)
        for k in range(len(queries) + 1):
            cov = [0] * n
            for l, r, val in queries[:k]:
                for i in range(l, r + 1):
                    cov[i] += val
            if all(cov[i] >= nums[i] for i in range(n)):
                return k
        return -1

