class Solution:
    def minZeroArray(self, nums, queries):
        n = len(nums)
        m = len(queries)

        def feasible(k):
            diff = [0] * (n + 1)
            for i in range(k):
                l, r, val = queries[i]
                diff[l] += val
                diff[r + 1] -= val
            cov = 0
            for i in range(n):
                cov += diff[i]
                if cov < nums[i]:
                    return False
            return True

        if not feasible(m):
            return -1
        lo, hi = 0, m
        while lo < hi:
            mid = (lo + hi) // 2
            if feasible(mid):
                hi = mid
            else:
                lo = mid + 1
        return lo

