var minZeroArray = function(nums, queries) {
    const n = nums.length, m = queries.length;
    const feasible = (k) => {
        const diff = new Array(n + 1).fill(0);
        for (let i = 0; i < k; i++) {
            const [l, r, val] = queries[i];
            diff[l] += val;
            diff[r + 1] -= val;
        }
        let cov = 0;
        for (let i = 0; i < n; i++) {
            cov += diff[i];
            if (cov < nums[i]) return false;
        }
        return true;
    };
    if (!feasible(m)) return -1;
    let lo = 0, hi = m;
    while (lo < hi) {
        const mid = (lo + hi) >> 1;
        if (feasible(mid)) hi = mid; else lo = mid + 1;
    }
    return lo;
};
